import android.content.Context
import android.content.Intent
import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity
import com.facebook.CallbackManager
import com.facebook.FacebookCallback
import com.facebook.FacebookException
import com.facebook.login.LoginManager
import com.facebook.login.LoginResult
import com.google.android.gms.auth.api.signin.GoogleSignIn
import com.google.android.gms.auth.api.signin.GoogleSignInAccount
import com.google.android.gms.auth.api.signin.GoogleSignInClient
import com.google.android.gms.auth.api.signin.GoogleSignInOptions
import com.google.android.gms.common.api.ApiException
import com.google.android.gms.tasks.Task
import java.util.*

class SocialLoginManager(private val context: Context) {
    private val facebookCallbackManager = CallbackManager.Factory.create()
    private var googleSignInClient: GoogleSignInClient? = null

    init {
        setupGoogleSignIn()
    }

    private fun setupGoogleSignIn() {
        val gso = GoogleSignInOptions.Builder(GoogleSignInOptions.DEFAULT_SIGN_IN)
            .requestEmail()
            .requestIdToken("1234-abcdef.apps.googleusercontent.com")
            .build()
        googleSignInClient = GoogleSignIn.getClient(context, gso)
    }

    fun handleFacebookResult(requestCode: Int, resultCode: Int, data: Intent?) {
        facebookCallbackManager.onActivityResult(requestCode, resultCode, data)
    }

    fun signInWithFacebook(activity: AppCompatActivity, callback: (result: SocialLoginResult) -> Unit) {
        LoginManager.getInstance().logInWithReadPermissions(activity, Arrays.asList("public_profile", "email"))
        LoginManager.getInstance().registerCallback(facebookCallbackManager, object : FacebookCallback<LoginResult> {
            override fun onSuccess(result: LoginResult) {
                callback(SocialLoginResult.Success("Facebook", result.accessToken.token))
            }

            override fun onCancel() {
                callback(SocialLoginResult.Error("Facebook login cancelled"))
            }

            override fun onError(error: FacebookException) {
                callback(SocialLoginResult.Error("Facebook login error: ${error.message}"))
            }
        })
    }

    fun signInWithGoogle(activity: AppCompatActivity, callback: (result: SocialLoginResult) -> Unit) {
        val signInIntent = googleSignInClient?.signInIntent
        activity.startActivityForResult(signInIntent, RC_GOOGLE_SIGN_IN)
        GoogleSignIn.getSignedInAccountFromIntent(signInIntent)
            .addOnCompleteListener(activity) { task: Task<GoogleSignInAccount> ->
                if (task.isSuccessful) {
                    val account = task.getResult(ApiException::class.java)
                    account?.let {
                        callback(SocialLoginResult.Success("Google", it.idToken ?: ""))
                    }
                } else {
                    callback(SocialLoginResult.Error("Google login failed"))
                }
            }
    }

    companion object {
        private const val RC_GOOGLE_SIGN_IN = 9001
    }
}

sealed class SocialLoginResult {
    data class Success(val provider: String, val token: String) : SocialLoginResult()
    data class Error(val message: String) : SocialLoginResult()
}

class SocialLoginActivity : AppCompatActivity() {
    private val socialLoginManager = SocialLoginManager(this)

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_social_login)
    }

    override fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        super.onActivityResult(requestCode, resultCode, data)
        socialLoginManager.handleFacebookResult(requestCode, resultCode, data)
